# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, request, redirect, session, url_for
import requests
import json
import base64
import urllib.parse
import secrets
import hashlib

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Configuration
OIDC_CONFIG = {
    'issuer': 'https://your-oidc-provider.com',
    'client_id': 'your_client_id',
    'client_secret': 'your_client_secret',
    'redirect_uri': 'http://localhost:5000/callback',
    'scope': 'openid profile email'
}

def get_oidc_config():
    return OIDC_CONFIG

def get_authorization_url():
    config = get_oidc_config()
    issuer = config['issuer']
    
    # Discover endpoints
    discovery_url = f"{issuer}/.well-known/openid-configuration"
    discovery_response = requests.get(discovery_url)
    discovery_data = discovery_response.json()
    
    auth_endpoint = discovery_data['authorization_endpoint']
    
    # Generate state and nonce
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    
    session['oidc_state'] = state
    session['oidc_nonce'] = nonce
    
    params = {
        'response_type': 'code',
        'client_id': config['client_id'],
        'redirect_uri': config['redirect_uri'],
        'scope': config['scope'],
        'state': state,
        'nonce': nonce
    }
    
    return f"{auth_endpoint}?{urllib.parse.urlencode(params)}"

@app.route('/')
def index():
    return '<a href="/login">Login with OIDC</a>'

@app.route('/login')
def login():
    auth_url = get_authorization_url()
    return redirect(auth_url)

@app.route('/callback')
def callback():
    config = get_oidc_config()
    
    # Validate state
    if request.args.get('state') != session.get('oidc_state'):
        return 'Invalid state parameter', 400
    
    # Exchange authorization code for tokens
    code = request.args.get('code')
    
    token_url = f"{config['issuer']}/oauth2/token"
    
    token_data = {
        'grant_type': 'authorization_code',
        'client_id': config['client_id'],
        'client_secret': config['client_secret'],
        'redirect_uri': config['redirect_uri'],
        'code': code
    }
    
    token_response = requests.post(token_url, data=token_data)
    token_data = token_response.json()
    
    # Decode id_token
    id_token = token_data.get('id_token')
    if not id_token:
        return 'No id_token received', 400
    
    # Split the JWT token
    header, payload, signature = id_token.split('.')
    
    # Add padding if necessary
    payload += '=' * (4 - len(payload) % 4)
    
    # Decode payload
    decoded_payload = base64.urlsafe_b64decode(payload)
    user_claims = json.loads(decoded_payload)
    
    # Validate nonce
    if user_claims.get('nonce') != session.get('oidc_nonce'):
        return 'Invalid nonce', 400
    
    # Store user info in session
    session['user'] = {
        'sub': user_claims.get('sub'),
        'name': user_claims.get('name'),
        'email': user_claims.get('email'),
        'preferred_username': user_claims.get('preferred_username')
    }
    
    return redirect('/dashboard')

@app.route('/dashboard')
def dashboard():
    user = session.get('user')
    if not user:
        return redirect('/login')
    
    return f"Welcome {user.get('name', 'User')}! <a href='/logout'>Logout</a>"

@app.route('/logout')
def logout():
    session.clear()
    return redirect('/')

if __name__ == '__main__':
    app.run(debug=True)